from claw.strategy import Strategy

class MyStrategy(Strategy):
    def setup(self):
        self.fast = self.indicator('SMA', period=10)
        self.slow = self.indicator('SMA', period=30)
    def on_bar(self, bar):
        if self.fast.iloc[-1] > self.slow.iloc[-1]:
            self.buy(size=1)
        else:
            self.sell(size=1)
